// 2.7.1 | 2021-12-21 | RAJ | DFCT0010724	Template Sub Task "Duration Warning" NOT triggered when parent is updated
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	// STRY0113048
	var afterParent = new TaskTemplateHelpers().isAfterParent(current);
	current.u_warning_projected_due_date_after_parent = afterParent;
	// DFCT0010724
	var beforeChild = new TaskTemplateHelpers().isBeforeChild(current);
	current.u_warning_projected_due_date_before_child = beforeChild;
})(current, previous);
